using UnityEngine;

public class CollisionExample : MonoBehaviour
{
    public int health = 100;
    public int damage = 20;

    // --- Collision Methods ---

    void OnCollisionEnter2D(Collision2D collision)
    {
        // Called when two colliders first touch
        Debug.Log("Collision with: " + collision.gameObject.name);

        // Check the object's tag
        if (collision.gameObject.CompareTag("Enemy"))
        {
            health -= damage;
            Debug.Log("Hit by enemy! Health: " + health);
        }

        // Get the contact point
        ContactPoint2D contact = collision.contacts[0];
        Debug.Log("Contact point: " + contact.point);

        // Get the relative velocity
        float impactSpeed = collision.relativeVelocity.magnitude;
        Debug.Log("Impact speed: " + impactSpeed);

        // Access the other collider
        Collider2D otherCollider = collision.collider;
        Rigidbody2D otherRb = collision.rigidbody;

        // Get component from the other object
        HealthComponent targetHealth = collision.gameObject.GetComponent<HealthComponent>();
        if (targetHealth != null)
        {
            targetHealth.TakeDamage(damage);
        }
    }

    void OnCollisionStay2D(Collision2D collision)
    {
        // Called every frame while colliding
        // Good for: continuous damage, friction

        if (collision.gameObject.CompareTag("Enemy"))
        {
            // Take damage over time
            // health -= damage * Time.deltaTime;
        }
    }

    void OnCollisionExit2D(Collision2D collision)
    {
        Debug.Log("Collision ended with: " + collision.gameObject.name);
    }

    // --- Trigger Methods ---

    void OnTriggerEnter2D(Collider2D other)
    {
        Debug.Log("Entered trigger: " + other.gameObject.name);

        // Collect coins
        if (other.CompareTag("Coin"))
        {
            Coin coin = other.GetComponent<Coin>();
            if (coin != null)
            {
                // Add score, destroy coin
                Debug.Log("Collected coin!");
                Destroy(other.gameObject);
            }
        }

        // Checkpoints
        if (other.CompareTag("Checkpoint"))
        {
            Debug.Log("Checkpoint reached!");
            // Save game state
        }

        // Damage zones
        if (other.CompareTag("Lava"))
        {
            Debug.Log("Lava! Taking damage!");
            health -= 50;
        }
    }

    void OnTriggerStay2D(Collider2D other)
    {
        // Called every frame while inside a trigger

        if (other.CompareTag("Lava"))
        {
            // Continuous damage
            health -= 10 * Time.deltaTime;
        }
    }

    void OnTriggerExit2D(Collider2D other)
    {
        Debug.Log("Exited trigger: " + other.gameObject.name);

        if (other.CompareTag("Lava"))
        {
            Debug.Log("Out of lava!");
        }
    }
}

// Example: Collectible Coin
public class Coin : MonoBehaviour
{
    public int pointValue = 10;

    void Start()
    {
        // Make sure it's a trigger
        Collider2D col = GetComponent<Collider2D>();
        if (col != null)
        {
            col.isTrigger = true;
        }
    }

    // Optional: Animation
    void Update()
    {
        // Float and rotate animation
        transform.Rotate(0, 0, 90 * Time.deltaTime);
    }
}

